import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { Loader, Plus, Save, Trash2 } from 'lucide-react';
import api from '../../services/api';

const emptyItem = { productId: '', quantity: 1, price: 0 };

const SalesHistory = () => {
  const [rows, setRows] = useState([]);
  const [products, setProducts] = useState([]);
  const [customers, setCustomers] = useState([]);
  const [editingId, setEditingId] = useState(null);
  const [form, setForm] = useState({
    userId: Number(localStorage.getItem('userId')) || 1,
    customerId: '',
    saleDate: new Date().toISOString().slice(0, 10),
    items: [emptyItem],
  });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const [salesRes, productRes, customerRes] = await Promise.all([
        api.get('/sales'),
        api.get('/products'),
        api.get('/customers'),
      ]);
      setRows(salesRes.data || []);
      setProducts(productRes.data || []);
      setCustomers(customerRes.data || []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load sales.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const changeItem = (idx, key, value) => {
    const copy = [...form.items];
    copy[idx] = { ...copy[idx], [key]: value };
    setForm({ ...form, items: copy });
  };

  const addItem = () => setForm({ ...form, items: [...form.items, emptyItem] });
  const removeItem = (idx) => setForm({ ...form, items: form.items.filter((_, i) => i !== idx) });

  const computedTotal = useMemo(
    () => form.items.reduce((sum, i) => sum + (Number(i.quantity) || 0) * (Number(i.price) || 0), 0),
    [form.items]
  );

  const onSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError('');
    try {
      const payload = {
        userId: Number(form.userId) || 1,
        customerId: form.customerId ? Number(form.customerId) : null,
        saleDate: form.saleDate,
        items: form.items.map((i) => ({
          productId: Number(i.productId),
          quantity: Number(i.quantity),
          price: Number(i.price),
        })),
      };

      if (editingId) {
        await api.put(`/sales/${editingId}`, payload);
      } else {
        await api.post('/sales', payload);
      }

      setEditingId(null);
      setForm({ userId: Number(localStorage.getItem('userId')) || 1, customerId: '', saleDate: new Date().toISOString().slice(0, 10), items: [emptyItem] });
      await fetchData();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save sale.');
    } finally {
      setSaving(false);
    }
  };

  const onEdit = (row) => {
    setEditingId(row.saleId);
    setForm({
      userId: row.userId,
      customerId: row.customerId || '',
      saleDate: new Date(row.saleDate).toISOString().slice(0, 10),
      items: (row.saleDetails || []).map((d) => ({ productId: d.productId, quantity: d.quantity, price: d.price })),
    });
  };

  const onDelete = async (id) => {
    if (!window.confirm('Delete this sale? Stock will be restored.')) return;
    try {
      await api.delete(`/sales/${id}`);
      await fetchData();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to delete sale.');
    }
  };

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-900">Sales</h2>
      {error && <div className="p-3 text-sm border border-red-200 bg-red-50 text-red-700 rounded-lg">{error}</div>}

      <form onSubmit={onSubmit} className="bg-white border border-gray-200 rounded-xl p-4 space-y-3">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          <input type="number" value={form.userId} onChange={(e) => setForm({ ...form, userId: e.target.value })} className="px-3 py-2 border border-gray-300 rounded-lg" placeholder="User ID" required />
          <select value={form.customerId} onChange={(e) => setForm({ ...form, customerId: e.target.value })} className="px-3 py-2 border border-gray-300 rounded-lg">
            <option value="">Walk-in customer</option>
            {customers.map((c) => <option key={c.customerId} value={c.customerId}>{c.customerName}</option>)}
          </select>
          <input type="date" value={form.saleDate} onChange={(e) => setForm({ ...form, saleDate: e.target.value })} className="px-3 py-2 border border-gray-300 rounded-lg" required />
        </div>

        <div className="space-y-2">
          {form.items.map((item, idx) => (
            <div key={idx} className="grid grid-cols-1 md:grid-cols-4 gap-2">
              <select value={item.productId} onChange={(e) => changeItem(idx, 'productId', e.target.value)} className="px-3 py-2 border border-gray-300 rounded-lg" required>
                <option value="">Select product</option>
                {products.map((p) => <option key={p.productId} value={p.productId}>{p.productName}</option>)}
              </select>
              <input type="number" min="1" value={item.quantity} onChange={(e) => changeItem(idx, 'quantity', e.target.value)} className="px-3 py-2 border border-gray-300 rounded-lg" placeholder="Qty" required />
              <input type="number" min="0" step="0.01" value={item.price} onChange={(e) => changeItem(idx, 'price', e.target.value)} className="px-3 py-2 border border-gray-300 rounded-lg" placeholder="Price" required />
              <button type="button" onClick={() => removeItem(idx)} disabled={form.items.length === 1} className="px-3 py-2 rounded-lg bg-red-50 text-red-600 border border-red-200 disabled:opacity-40">Remove</button>
            </div>
          ))}
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <button type="button" onClick={addItem} className="inline-flex items-center gap-2 px-3 py-2 rounded-lg bg-gray-100 text-gray-700"><Plus className="w-4 h-4" /> Add Item</button>
          <div className="text-sm font-semibold text-gray-700">Total: ${computedTotal.toFixed(2)}</div>
          <button type="submit" disabled={saving} className="inline-flex items-center gap-2 px-4 py-2 rounded-lg bg-blue-600 text-white"><Save className="w-4 h-4" /> {editingId ? 'Update' : 'Create'}</button>
          {editingId && <button type="button" onClick={() => { setEditingId(null); setForm({ userId: Number(localStorage.getItem('userId')) || 1, customerId: '', saleDate: new Date().toISOString().slice(0, 10), items: [emptyItem] }); }} className="px-4 py-2 rounded-lg bg-gray-200">Cancel</button>}
        </div>
      </form>

      <div className="bg-white border border-gray-200 rounded-xl overflow-x-auto">
        {loading ? <div className="py-10 flex justify-center"><Loader className="w-6 h-6 animate-spin text-blue-600" /></div> : (
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Date</th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Customer</th>
                <th className="px-4 py-3 text-right text-xs font-semibold text-gray-700 uppercase">Items</th>
                <th className="px-4 py-3 text-right text-xs font-semibold text-gray-700 uppercase">Total</th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Actions</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((r) => (
                <tr key={r.saleId} className="border-t border-gray-100">
                  <td className="px-4 py-3">{new Date(r.saleDate).toLocaleDateString()}</td>
                  <td className="px-4 py-3">{r.customer?.customerName || 'Walk-in'}</td>
                  <td className="px-4 py-3 text-right">{(r.saleDetails || []).length}</td>
                  <td className="px-4 py-3 text-right font-semibold">${Number(r.totalAmount || 0).toFixed(2)}</td>
                  <td className="px-4 py-3">
                    <div className="flex gap-2">
                      <button onClick={() => onEdit(r)} className="px-3 py-1 rounded bg-blue-50 text-blue-600">Edit</button>
                      <button onClick={() => onDelete(r.saleId)} className="inline-flex items-center gap-1 px-3 py-1 rounded bg-red-50 text-red-600"><Trash2 className="w-3 h-3" />Delete</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default SalesHistory;
